settings.custom_liquid:
{% if product.tags contains 'hugbel100' %}

<div style="margin:12px 0 10px 0; font-family:inherit;">

  <div style="
    display:flex;
    align-items:center;
    gap:10px;
  ">

    <!-- enhanced pulsing green dot -->
    <span 
      style="
        width:14px;
        height:14px;
        border-radius:50%;
        background:#34a36f; /* premium green */
        box-shadow:0 0 0 4px rgba(52,163,111,0.28); /* stronger halo */
        display:inline-block;
        animation:hugbelGreenPulse 1.4s ease-in-out infinite;
        flex-shrink:0;
      ">
    </span>

    <!-- punchy bestseller line -->
    <span style="
      font-size:1.3rem;
      font-weight:500;
      line-height:1.25;
      color:#2b2b2b;
      letter-spacing:0.005em;
    ">
      Best seller – only a few left
    </span>

  </div>

</div>

<style>
  @keyframes hugbelGreenPulse {
    0%   { transform:scale(1); opacity:1; }
    50%  { transform:scale(1.25); opacity:0.55; } /* more obvious pulse */
    100% { transform:scale(1); opacity:1; }
  }
</style>

{% endif %}

{% if product.available %}
  <div class="hugbel-stock-inline" role="status" aria-live="polite">
    <span class="hugbel-dot" aria-hidden="true"></span>
    <span class="hugbel-text">
      <strong>In stock</strong> 
    </span>
  </div>

  <style>
    .hugbel-stock-inline{
      display:flex;
      align-items:flex-start;
      gap:10px;
      margin:12px 0;
      font-size:14px;
      line-height:1.35;
    }
    .hugbel-dot{
      width:10px;
      height:10px;
      border-radius:50%;
      background:#1db954;
      box-shadow:0 0 0 3px rgba(29,185,84,.15);
      margin-top:4px;
      flex:0 0 auto;
    }
    .hugbel-text{
      color:rgba(0,0,0,.78);
    }
    .hugbel-date{
      font-weight:700;
      padding:1px 6px;
      border-radius:999px;
      background:rgba(0,0,0,.06);
      white-space:nowrap;
    }
  </style>
{% endif %}
